<template>
  <div class="work-order-page">
    <el-card class="page-card">
      <template #header>
        <div class="card-header">
          <div class="header-left">
            <span class="title">工单管理</span>
            <el-tag type="info" size="small" class="sync-status">
              <el-icon><Connection /></el-icon>
              SAP同步: {{ sapSyncStatus }}
            </el-tag>
          </div>
          <div class="header-actions">
            <el-button type="success" @click="handleImportFromSAP" :loading="importLoading">
              <el-icon><Download /></el-icon>
              从SAP导入
            </el-button>
            <el-button type="primary" @click="handleCreate">
              <el-icon><Plus /></el-icon>
              创建工单
            </el-button>
          </div>
        </div>
      </template>

      <!-- 筛选栏 -->
      <div class="filter-bar">
        <el-radio-group v-model="filterStatus" @change="handleFilterChange">
          <el-radio-button label="">全部</el-radio-button>
          <el-radio-button label="执行中">执行中</el-radio-button>
          <el-radio-button label="已完成">已完成</el-radio-button>
        </el-radio-group>
        <el-input
          v-model="searchKeyword"
          placeholder="搜索工单号/产品名称"
          clearable
          style="width: 250px; margin-left: 16px;"
        >
          <template #prefix>
            <el-icon><Search /></el-icon>
          </template>
        </el-input>
      </div>

      <!-- 工单表格 -->
      <el-table
        :data="filteredWorkOrders"
        stripe
        border
        style="width: 100%; margin-top: 20px;"
        v-loading="loading"
      >
        <el-table-column prop="workOrderNo" label="工单号" width="150" />
        <el-table-column prop="type" label="类型" width="100">
          <template #default="{ row }">
            <el-tag :type="row.type === '返修' ? 'warning' : 'success'">
              {{ row.type }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="productCode" label="产品编码" width="120" />
        <el-table-column prop="productName" label="产品名称" min-width="150" show-overflow-tooltip />
        <el-table-column prop="quantity" label="数量" width="100" align="center" />
        <el-table-column prop="productionLine" label="产线" width="120" />
        <el-table-column prop="status" label="状态" width="100">
          <template #default="{ row }">
            <el-tag :type="getStatusType(row.status)">
              {{ row.status }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="priority" label="优先级" width="100">
          <template #default="{ row }">
            <el-tag :type="getPriorityType(row.priority)" effect="dark" size="small">
              {{ row.priority }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="plannedTime" label="计划时间" width="180" />
        <el-table-column label="操作" width="150" fixed="right">
          <template #default="{ row }">
            <el-button type="primary" link size="small" @click="handleEdit(row)">
              编辑
            </el-button>
            <el-button type="danger" link size="small" @click="handleDelete(row)">
              删除
            </el-button>
          </template>
        </el-table-column>
      </el-table>

      <!-- 分页 -->
      <div class="pagination-wrapper">
        <el-pagination
          v-model:current-page="currentPage"
          v-model:page-size="pageSize"
          :page-sizes="[10, 20, 50, 100]"
          :total="total"
          layout="total, sizes, prev, pager, next, jumper"
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
        />
      </div>
    </el-card>

    <!-- 创建/编辑工单对话框 -->
    <el-dialog
      v-model="dialogVisible"
      :title="isEdit ? '编辑工单' : '创建工单'"
      width="600px"
      destroy-on-close
    >
      <el-form
        ref="formRef"
        :model="formData"
        :rules="formRules"
        label-width="100px"
        class="work-order-form"
      >
        <el-row :gutter="20">
          <el-col :span="12">
            <el-form-item label="工单号" prop="workOrderNo">
              <el-input v-model="formData.workOrderNo" placeholder="请输入工单号" />
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="类型" prop="type">
              <el-select v-model="formData.type" placeholder="请选择类型" style="width: 100%;">
                <el-option label="正常" value="正常" />
                <el-option label="返修" value="返修" />
              </el-select>
            </el-form-item>
          </el-col>
        </el-row>
        <el-row :gutter="20">
          <el-col :span="12">
            <el-form-item label="产品编码" prop="productCode">
              <el-input v-model="formData.productCode" placeholder="请输入产品编码" />
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="产品名称" prop="productName">
              <el-input v-model="formData.productName" placeholder="请输入产品名称" />
            </el-form-item>
          </el-col>
        </el-row>
        <el-row :gutter="20">
          <el-col :span="12">
            <el-form-item label="数量" prop="quantity">
              <el-input-number v-model="formData.quantity" :min="1" style="width: 100%;" />
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="产线" prop="productionLine">
              <el-select v-model="formData.productionLine" placeholder="请选择产线" style="width: 100%;">
                <el-option label="A产线" value="A产线" />
                <el-option label="B产线" value="B产线" />
                <el-option label="C产线" value="C产线" />
                <el-option label="D产线" value="D产线" />
              </el-select>
            </el-form-item>
          </el-col>
        </el-row>
        <el-row :gutter="20">
          <el-col :span="12">
            <el-form-item label="状态" prop="status">
              <el-select v-model="formData.status" placeholder="请选择状态" style="width: 100%;">
                <el-option label="执行中" value="执行中" />
                <el-option label="已完成" value="已完成" />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="优先级" prop="priority">
              <el-select v-model="formData.priority" placeholder="请选择优先级" style="width: 100%;">
                <el-option label="高" value="高" />
                <el-option label="中" value="中" />
                <el-option label="低" value="低" />
              </el-select>
            </el-form-item>
          </el-col>
        </el-row>
        <el-form-item label="计划时间" prop="plannedTime">
          <el-date-picker
            v-model="formData.plannedTime"
            type="datetime"
            placeholder="选择计划时间"
            style="width: 100%;"
            value-format="YYYY-MM-DD HH:mm:ss"
          />
        </el-form-item>
      </el-form>
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="dialogVisible = false">取消</el-button>
          <el-button type="primary" @click="handleSubmit" :loading="submitLoading">
            确定
          </el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { Plus, Search, Connection, Download } from '@element-plus/icons-vue'
import type { FormInstance, FormRules } from 'element-plus'

// 工单类型定义
interface WorkOrder {
  id: number
  workOrderNo: string
  type: '正常' | '返修'
  productCode: string
  productName: string
  quantity: number
  productionLine: string
  status: '执行中' | '已完成'
  priority: '高' | '中' | '低'
  plannedTime: string
}

// Mock 数据
const mockWorkOrders: WorkOrder[] = [
  {
    id: 1,
    workOrderNo: 'WO20240605001',
    type: '正常',
    productCode: 'PRD001',
    productName: '智能手机 A1',
    quantity: 1000,
    productionLine: 'A产线',
    status: '执行中',
    priority: '高',
    plannedTime: '2024-06-10 08:00:00'
  },
  {
    id: 2,
    workOrderNo: 'WO20240605002',
    type: '正常',
    productCode: 'PRD002',
    productName: '平板电脑 B2',
    quantity: 500,
    productionLine: 'B产线',
    status: '执行中',
    priority: '中',
    plannedTime: '2024-06-12 09:00:00'
  },
  {
    id: 3,
    workOrderNo: 'WO20240605003',
    type: '返修',
    productCode: 'PRD001',
    productName: '智能手机 A1',
    quantity: 50,
    productionLine: 'C产线',
    status: '执行中',
    priority: '高',
    plannedTime: '2024-06-08 10:00:00'
  },
  {
    id: 4,
    workOrderNo: 'WO20240605004',
    type: '正常',
    productCode: 'PRD003',
    productName: '智能手表 C3',
    quantity: 2000,
    productionLine: 'A产线',
    status: '已完成',
    priority: '低',
    plannedTime: '2024-06-05 08:00:00'
  },
  {
    id: 5,
    workOrderNo: 'WO20240605005',
    type: '正常',
    productCode: 'PRD004',
    productName: '无线耳机 D4',
    quantity: 3000,
    productionLine: 'D产线',
    status: '执行中',
    priority: '中',
    plannedTime: '2024-06-15 08:00:00'
  },
  {
    id: 6,
    workOrderNo: 'WO20240605006',
    type: '返修',
    productCode: 'PRD002',
    productName: '平板电脑 B2',
    quantity: 30,
    productionLine: 'B产线',
    status: '已完成',
    priority: '低',
    plannedTime: '2024-06-06 14:00:00'
  },
  {
    id: 7,
    workOrderNo: 'WO20240605007',
    type: '正常',
    productCode: 'PRD005',
    productName: '智能音箱 E5',
    quantity: 800,
    productionLine: 'C产线',
    status: '执行中',
    priority: '高',
    plannedTime: '2024-06-11 08:00:00'
  },
  {
    id: 8,
    workOrderNo: 'WO20240605008',
    type: '正常',
    productCode: 'PRD006',
    productName: '路由器 F6',
    quantity: 1500,
    productionLine: 'D产线',
    status: '已完成',
    priority: '中',
    plannedTime: '2024-06-04 08:00:00'
  }
]

// 响应式数据
const loading = ref(false)
const workOrders = ref<WorkOrder[]>([])
const filterStatus = ref('')
const searchKeyword = ref('')
const currentPage = ref(1)
const pageSize = ref(10)
const total = ref(0)
const sapSyncStatus = ref('已连接')
const importLoading = ref(false)

// 对话框相关
const dialogVisible = ref(false)
const isEdit = ref(false)
const submitLoading = ref(false)
const formRef = ref<FormInstance>()
const formData = ref<Partial<WorkOrder>>({
  workOrderNo: '',
  type: '正常',
  productCode: '',
  productName: '',
  quantity: 1,
  productionLine: '',
  status: '执行中',
  priority: '中',
  plannedTime: ''
})

// 表单验证规则
const formRules: FormRules = {
  workOrderNo: [{ required: true, message: '请输入工单号', trigger: 'blur' }],
  type: [{ required: true, message: '请选择类型', trigger: 'change' }],
  productCode: [{ required: true, message: '请输入产品编码', trigger: 'blur' }],
  productName: [{ required: true, message: '请输入产品名称', trigger: 'blur' }],
  quantity: [{ required: true, message: '请输入数量', trigger: 'blur' }],
  productionLine: [{ required: true, message: '请选择产线', trigger: 'change' }],
  status: [{ required: true, message: '请选择状态', trigger: 'change' }],
  priority: [{ required: true, message: '请选择优先级', trigger: 'change' }],
  plannedTime: [{ required: true, message: '请选择计划时间', trigger: 'change' }]
}

// 计算属性：筛选后的工单列表
const filteredWorkOrders = computed(() => {
  let result = workOrders.value

  // 按状态筛选
  if (filterStatus.value) {
    result = result.filter(item => item.status === filterStatus.value)
  }

  // 按关键词搜索
  if (searchKeyword.value) {
    const keyword = searchKeyword.value.toLowerCase()
    result = result.filter(item =>
      item.workOrderNo.toLowerCase().includes(keyword) ||
      item.productName.toLowerCase().includes(keyword)
    )
  }

  return result
})

// 获取状态标签类型
const getStatusType = (status: string) => {
  switch (status) {
    case '执行中':
      return 'primary'
    case '已完成':
      return 'success'
    default:
      return 'info'
  }
}

// 获取优先级标签类型
const getPriorityType = (priority: string) => {
  switch (priority) {
    case '高':
      return 'danger'
    case '中':
      return 'warning'
    case '低':
      return 'info'
    default:
      return 'info'
  }
}

// 加载数据
const loadData = () => {
  loading.value = true
  // 模拟异步加载
  setTimeout(() => {
    workOrders.value = mockWorkOrders
    total.value = mockWorkOrders.length
    loading.value = false
  }, 500)
}

// 筛选变化
const handleFilterChange = () => {
  currentPage.value = 1
}

// 分页大小变化
const handleSizeChange = (val: number) => {
  pageSize.value = val
  currentPage.value = 1
}

// 页码变化
const handleCurrentChange = (val: number) => {
  currentPage.value = val
}

// 创建工单
const handleCreate = () => {
  isEdit.value = false
  formData.value = {
    workOrderNo: generateWorkOrderNo(),
    type: '正常',
    productCode: '',
    productName: '',
    quantity: 1,
    productionLine: '',
    status: '执行中',
    priority: '中',
    plannedTime: ''
  }
  dialogVisible.value = true
}

// 编辑工单
const handleEdit = (row: WorkOrder) => {
  isEdit.value = true
  formData.value = { ...row }
  dialogVisible.value = true
}

// 删除工单
const handleDelete = (row: WorkOrder) => {
  ElMessageBox.confirm(
    `确定要删除工单 "${row.workOrderNo}" 吗？`,
    '提示',
    {
      confirmButtonText: '确定',
      cancelButtonText: '取消',
      type: 'warning'
    }
  ).then(() => {
    const index = workOrders.value.findIndex(item => item.id === row.id)
    if (index > -1) {
      workOrders.value.splice(index, 1)
      total.value--
      ElMessage.success('删除成功')
    }
  }).catch(() => {
    // 取消删除
  })
}

// 提交表单
const handleSubmit = async () => {
  if (!formRef.value) return

  await formRef.value.validate((valid) => {
    if (valid) {
      submitLoading.value = true
      // 模拟提交
      setTimeout(() => {
        if (isEdit.value) {
          // 编辑模式
          const index = workOrders.value.findIndex(item => item.id === formData.value.id)
          if (index > -1) {
            workOrders.value[index] = { ...formData.value as WorkOrder }
            ElMessage.success('编辑成功')
          }
        } else {
          // 创建模式
          const newOrder: WorkOrder = {
            ...formData.value as WorkOrder,
            id: Date.now()
          }
          workOrders.value.unshift(newOrder)
          total.value++
          ElMessage.success('创建成功')
        }
        dialogVisible.value = false
        submitLoading.value = false
      }, 500)
    }
  })
}

// 生成工单号
const generateWorkOrderNo = () => {
  const date = new Date()
  const dateStr = date.toISOString().slice(0, 10).replace(/-/g, '')
  const randomNum = Math.floor(Math.random() * 900) + 100
  return `WO${dateStr}${randomNum}`
}

// 初始化
onMounted(() => {
  loadData()
})

// 从SAP导入工单
const handleImportFromSAP = () => {
  importLoading.value = true
  // 模拟从SAP导入数据
  setTimeout(() => {
    const sapWorkOrders: WorkOrder[] = [
      {
        id: Date.now(),
        workOrderNo: 'SAP' + generateWorkOrderNo(),
        type: '正常',
        productCode: 'SAP001',
        productName: 'SAP导入产品-基胶A',
        quantity: 5000,
        productionLine: 'A产线',
        status: '执行中',
        priority: '高',
        plannedTime: '2024-06-20 08:00:00'
      },
      {
        id: Date.now() + 1,
        workOrderNo: 'SAP' + generateWorkOrderNo(),
        type: '正常',
        productCode: 'SAP002',
        productName: 'SAP导入产品-调色液B',
        quantity: 3000,
        productionLine: 'B产线',
        status: '执行中',
        priority: '中',
        plannedTime: '2024-06-21 09:00:00'
      }
    ]
    workOrders.value.unshift(...sapWorkOrders)
    total.value += sapWorkOrders.length
    importLoading.value = false
    ElMessage.success('成功从SAP导入 ' + sapWorkOrders.length + ' 条工单')
  }, 1500)
}
</script>

<style scoped lang="scss">
.work-order-page {
  padding: 20px;
  background-color: #f5f7fa;
  min-height: calc(100vh - 60px);

  .page-card {
    .card-header {
      display: flex;
      justify-content: space-between;
      align-items: center;

      .header-left {
        display: flex;
        align-items: center;
        gap: 12px;

        .title {
          font-size: 18px;
          font-weight: 600;
          color: #303133;
        }

        .sync-status {
          display: flex;
          align-items: center;
          gap: 4px;
        }
      }

      .header-actions {
        display: flex;
        gap: 10px;
      }
    }
  }

  .filter-bar {
    display: flex;
    align-items: center;
    margin-bottom: 16px;
  }

  .pagination-wrapper {
    display: flex;
    justify-content: flex-end;
    margin-top: 20px;
    padding-top: 20px;
    border-top: 1px solid #ebeef5;
  }

  .work-order-form {
    padding: 10px 0;
  }
}

:deep(.el-card__header) {
  padding: 15px 20px;
  border-bottom: 1px solid #ebeef5;
}

:deep(.el-table) {
  .el-tag {
    font-weight: 500;
  }
}
</style>
